#include <bits/stdc++.h>
using namespace std;
int main(){int n;scanf("%d",&n);vector<long long>pos,neg;long long ones=0;bool zero=false;for(int i=0;i<n;i++){long long x;scanf("%lld",&x);if(x>1)pos.push_back(x);else if(x==1)ones++;else if(x==0)zero=true;else neg.push_back(x);}sort(pos.rbegin(),pos.rend());sort(neg.begin(),neg.end());long long sum=ones;for(size_t i=0;i<pos.size();i+=2){if(i+1<pos.size())sum+=pos[i]*pos[i+1];else sum+=pos[i];}for(size_t i=0;i<neg.size();i+=2){if(i+1<neg.size())sum+=neg[i]*neg[i+1];else if(!zero)sum+=neg[i];}printf("%lld\n",sum);}
